def my_sqrt(x: int) -> int:
    if x < 2:
        return x
    lo, hi = 1, x // 2 + 1
    ans = 1
    while lo <= hi:
        mid = (lo + hi) // 2
        sq = mid * mid
        if sq == x:
            return mid
        if sq < x:
            ans = mid
            lo = mid + 1
        else:
            hi = mid - 1
    return ans

